#include<bits/stdc++.h>
using namespace std;
long long n,ans;
string a;
long long t[200010][26],cnt[2<<27];
int main(){
    cin>>n;
    cin>>a;
    a=' '+a;
    for(int i=1;i<=n;i++){
            for(int k=0;k<26;k++){
                t[i][k]=t[i-1][k];
            }
        t[i][a[i]-'a']++;
    }
    for(int i=0;i<=n;i++){
            int cns=0;
                int j=1;;
            for(int k=0;k<26;k++){
                if(t[i][k]%2==1){
                    cns+=j;
                }
                j*=2;
            }
            ans+=cnt[cns];
        cnt[cns]++;

    }
    cout<<ans;
    return 0;
}
